1	package main
2	
3	import (
4		"fmt"
5		"io"
6		"os"
7		"path/filepath"
8		"slices"
9		"sort"
10		"strings"
11	
12		"github.com/pdfcpu/pdfcpu/pkg/api"
13	)
14	
15	// mergePDFs interleaves pages from pathA and pathB into outPath.
16	// If firstPageInA is true, file A contributes the odd-numbered output pages (1, 3, 5, …);
17	// otherwise file B does. If reverseB is true, file B's pages are reversed before interleaving,
18	// which is the typical case when the paper stack was flipped between scans.
19	// If the page counts differ, the extra pages from the longer file are
20	// appended in order after the interleaved section.
21	func mergePDFs(pathA, pathB, outPath string, firstPageInA, reverseB bool, skipA, skipB []int, rotationsA, rotationsB map[int]int) error {
22		tmpDir, err := os.MkdirTemp("", "psp-merge-*")
23		if err != nil {
24			return err
25		}
26		defer os.RemoveAll(tmpDir)
27	
28		dirA := filepath.Join(tmpDir, "a")
29		dirB := filepath.Join(tmpDir, "b")
30		for _, d := range []string{dirA, dirB} {
31			if err := os.MkdirAll(d, 0o755); err != nil {
32				return err
33			}
34		}
35	
36		if err := api.SplitFile(pathA, dirA, 1, nil); err != nil {
37			return fmt.Errorf("splitting file A: %w", err)
38		}
39		if err := api.SplitFile(pathB, dirB, 1, nil); err != nil {
40			return fmt.Errorf("splitting file B: %w", err)
41		}
42	
43		pagesA, err := sortedPDFsInDir(dirA)
44		if err != nil {
45			return fmt.Errorf("listing file A pages: %w", err)
46		}
47		pagesB, err := sortedPDFsInDir(dirB)
48		if err != nil {
49			return fmt.Errorf("listing file B pages: %w", err)
50		}
51	
52		pagesA = filterSkipped(pagesA, skipA)
53		pagesB = filterSkipped(pagesB, skipB)
54		if reverseB {
55			slices.Reverse(pagesB)
56		}
57	
58		if err := applyRotations(pagesA, rotationsA); err != nil {
59			return fmt.Errorf("rotating file A pages: %w", err)
60		}
61		if err := applyRotations(pagesB, rotationsB); err != nil {
62			return fmt.Errorf("rotating file B pages: %w", err)
63		}
64	
65		if firstPageInA {
66			return api.MergeCreateFile(interleave(pagesA, pagesB), outPath, false, nil)
67		}
68		return api.MergeCreateFile(interleave(pagesB, pagesA), outPath, false, nil)
69	}
70	
71	func filterSkipped(pages []string, skip []int) []string {
72		if len(skip) == 0 {
73			return pages
74		}
75		skipSet := make(map[int]bool, len(skip))
76		for _, p := range skip {
77			skipSet[p] = true
78		}
79		out := make([]string, 0, len(pages))
80		for i, p := range pages {
81			if !skipSet[i+1] {
82				out = append(out, p)
83			}
84		}
85		return out
86	}
87	
88	// applyRotations rotates individual single-page PDF files in-place according to
89	// the rotations map (1-indexed page number → clockwise degrees: 90, 180, 270).
90	// The page number is derived from the pdfcpu split filename.
91	func applyRotations(pages []string, rotations map[int]int) error {
92		for _, p := range pages {
93			origPage := pdfFromPage(filepath.Base(p))
94			rot, ok := rotations[origPage]
95			if !ok || rot == 0 {
96				continue
97			}
98			tmp := p + ".rot.pdf"
99			if err := api.RotateFile(p, tmp, rot, nil, nil); err != nil {
100				return fmt.Errorf("page %d: %w", origPage, err)
101			}
102			if err := os.Rename(tmp, p); err != nil {
103				return err
104			}
105		}
106		return nil
107	}
108	
109	// splitPDF splits the PDF at inPath at the given page boundaries and writes
110	// each segment to outDir, returning the output file paths in order.
111	// splitAfter contains 1-indexed page numbers after which a new file begins.
112	// E.g. splitAfter=[2,4] on a 6-page PDF produces three files: pages 1-2, 3-4, 5-6.
113	// skip contains 1-indexed page numbers to exclude from all output files.
114	// rotations maps 1-indexed original page numbers to clockwise degrees (90, 180, 270).
115	func splitPDF(inPath string, splitAfter []int, skip []int, rotations map[int]int, outDir string) ([]string, error) {
116		if len(skip) == 0 {
117			// Fast path: rotate the whole file once then use pdfcpu's native split.
118			src := inPath
119			if len(rotations) > 0 {
120				// Rotate before splitting so SplitByPageNrFile operates on the final pages.
121				// Use a subdirectory so sortedPDFsInDir(outDir) doesn't pick up this file.
122				preDir := filepath.Join(outDir, "pre")
123				if err := os.MkdirAll(preDir, 0o755); err != nil {
124					return nil, err
125				}
126				rotated := filepath.Join(preDir, "rotated.pdf")
127				if err := applyRotationsToFile(inPath, rotated, rotations); err != nil {
128					return nil, err
129				}
130				src = rotated
131			}
132	
133			if len(splitAfter) == 0 {
134				outPath := filepath.Join(outDir, "output.pdf")
135				if err := copyFile(src, outPath); err != nil {
136					return nil, err
137				}
138				return []string{outPath}, nil
139			}
140	
141			// SplitByPageNrFile expects the first page of each new segment.
142			pageNrs := make([]int, len(splitAfter))
143			for i, p := range splitAfter {
144				pageNrs[i] = p + 1
145			}
146			if err := api.SplitByPageNrFile(src, outDir, pageNrs, nil); err != nil {
147				return nil, fmt.Errorf("splitting PDF: %w", err)
148			}
149			return sortedPDFsInDir(outDir)
150		}
151	
152		// Skip path: explode to single pages, filter, rotate, then reassemble each segment.
153		tmpDir, err := os.MkdirTemp("", "psp-split-pages-*")
154		if err != nil {
155			return nil, err
156		}
157		defer os.RemoveAll(tmpDir)
158	
159		if err := api.SplitFile(inPath, tmpDir, 1, nil); err != nil {
160			return nil, fmt.Errorf("splitting to single pages: %w", err)
161		}
162		allPages, err := sortedPDFsInDir(tmpDir)
163		if err != nil {
164			return nil, fmt.Errorf("listing single pages: %w", err)
165		}
166		pageCount := len(allPages)
167	
168		if err := applyRotations(allPages, rotations); err != nil {
169			return nil, fmt.Errorf("rotating pages: %w", err)
170		}
171	
172		skipSet := make(map[int]bool, len(skip))
173		for _, p := range skip {
174			skipSet[p] = true
175		}
176	
177		// Build segment start-page list (1-indexed).
178		starts := make([]int, 0, len(splitAfter)+1)
179		starts = append(starts, 1)
180		for _, p := range splitAfter {
181			starts = append(starts, p+1)
182		}
183	
184		var outPaths []string
185		for i, start := range starts {
186			end := pageCount
187			if i+1 < len(starts) {
188				end = starts[i+1] - 1
189			}
190			var segPages []string
191			for page := start; page <= end; page++ {
192				if !skipSet[page] {
193					segPages = append(segPages, allPages[page-1])
194				}
195			}
196			if len(segPages) == 0 {
197				return nil, fmt.Errorf("output file %d has no pages after applying skip", i+1)
198			}
199			outPath := filepath.Join(outDir, fmt.Sprintf("segment-%d.pdf", i+1))
200			if err := api.MergeCreateFile(segPages, outPath, false, nil); err != nil {
201				return nil, fmt.Errorf("building segment %d: %w", i+1, err)
202			}
203			outPaths = append(outPaths, outPath)
